import React, { useEffect, useState } from "react";
import { useSheetData } from "../05_SheetDataContext";
import { updateValueAtPath } from "../sheetStateUtils";

const initializeDots = (length, filledCount) => {
  return Array.from({ length }, (_, i) => i < filledCount);
};

const getEnergyColor = (race) => {
  const raceColors = {
    mage: "bg-cyan-500 border-cyan-500",
    vampire: "bg-rose-600 border-rose-600",
    werewolf: "bg-violet-500 border-violet-500",
    changeling: "bg-pink-500 border-pink-500",
    geist: "bg-gray-500 border-gray-500",
    mummy: "bg-yellow-500 border-yellow-500",
    promethean: "bg-yellow-500 border-yellow-500",
  };
  return raceColors[race] || "bg-blue-500 border-blue-500";
};

export const RaceEnergyTracker = ({ compact = false }) => {
  const { sheetData, setSheetData } = useSheetData();
  const selectedRace = sheetData.character.race.selected;
  const energyPoolName = sheetData.race_traits.race_specific_names[selectedRace]?.energy_pool;
  const maxEnergy = sheetData.race_traits.energy_pool.max;
  const currentEnergy = sheetData.race_traits.energy_pool.current;
  const [energyPool, setEnergyPool] = useState(() =>
    initializeDots(maxEnergy, currentEnergy)
  );
  const energyColor = getEnergyColor(selectedRace);

  useEffect(() => {
    setEnergyPool(initializeDots(maxEnergy, currentEnergy));
  }, [currentEnergy, maxEnergy]);

  useEffect(() => {
    const filledDots = energyPool.filter(Boolean).length;
    setSheetData((prev) =>
      updateValueAtPath(prev, ["race_traits", "energy_pool", "current"], filledDots)
    );
  }, [energyPool, setSheetData]);

  const setEnergyLevel = (index) => {
    setEnergyPool((prev) => {
      if (index === 0 && prev.filter(Boolean).length === 1 && prev[0]) {
        return prev.map(() => false);
      }

      return prev.map((_, i) => i <= index);
    });
  };

  return (
    <div className={`w-full ${energyPoolName ? "visible" : "invisible"}`}>
      {energyPoolName ? (
        <>
          <div className={compact ? "mb-2 flex items-center justify-between gap-2" : ""}>
            <h1
              className={`font-bold capitalize ${
                compact ? "text-sm" : "my-2 text-center text-l"
              }`}
            >
              {energyPoolName}
            </h1>
            {compact ? (
              <span className="text-xs text-gray-500">
                {currentEnergy}/{maxEnergy} - Per turn{" "}
                {sheetData.race_traits.energy_pool.per_turn}
              </span>
            ) : null}
          </div>
          <div className="flex items-center justify-center gap-4">
            <div className={`grid ${compact ? "grid-cols-5 gap-1 sm:grid-cols-10" : "grid-cols-10 gap-2"}`}>
              {energyPool.map((filled, i) => (
                <div key={i} className="relative flex items-center">
                  <div
                    className={`energy-box flex cursor-pointer items-center justify-center rounded-md border-2 transition-all duration-300 ${
                      compact ? "h-[20px] w-[20px]" : "h-[24px] w-[24px]"
                    } ${filled ? energyColor : "border-gray-400 bg-transparent"}`}
                    onClick={() => setEnergyLevel(i)}
                  />
                </div>
              ))}
            </div>
          </div>
          {!compact ? (
            <p className="mt-2 text-center">
              Per Turn: {sheetData.race_traits.energy_pool.per_turn}
            </p>
          ) : null}
        </>
      ) : null}
    </div>
  );
};
